import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"State Timeline","description":"","frontmatter":{},"headers":[],"relativePath":"guide/state-timeline.md","filePath":"guide/state-timeline.md"}'),p={name:"guide/state-timeline.md"};function i(l,e,r,o,c,h){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="state-timeline" tabindex="-1">State Timeline <a class="header-anchor" href="#state-timeline" aria-label="Permalink to &quot;State Timeline&quot;">​</a></h1><p>A state timeline is an ordered sequence of execution steps. Each step captures the complete program state at that moment — stack, heap, and what changed.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 1: SESSION_STARTED  → empty state</span></span>
<span class="line"><span>Step 2: METHOD_ENTERED   → main() frame pushed</span></span>
<span class="line"><span>Step 3: VARIABLE_ASSIGNED → x = 5</span></span>
<span class="line"><span>Step 4: VARIABLE_ASSIGNED → y = 10</span></span>
<span class="line"><span>Step 5: VARIABLE_ASSIGNED → z = 15</span></span>
<span class="line"><span>Step 6: METHOD_EXITED    → main() frame popped</span></span>
<span class="line"><span>Step 7: SESSION_FINISHED → empty state</span></span></code></pre></div><p>Each step contains:</p><ul><li><strong>Full materialized state</strong> — the complete picture at that moment</li><li><strong>Delta</strong> — what changed from the previous step</li><li><strong>Event type</strong> — what kind of thing happened</li><li><strong>Source anchor</strong> — which line of code caused it</li></ul><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><p>You can navigate a timeline in any direction:</p><ul><li><strong>Forward</strong> — step 3 → step 4 → step 5</li><li><strong>Backward</strong> — step 5 → step 4 → step 3</li><li><strong>Jump</strong> — go directly to step 12</li><li><strong>Filter</strong> — show only VARIABLE_ASSIGNED events</li></ul><h2 id="checkpoints" tabindex="-1">Checkpoints <a class="header-anchor" href="#checkpoints" aria-label="Permalink to &quot;Checkpoints&quot;">​</a></h2><p>For large traces, the engine creates periodic checkpoints — full state snapshots that enable fast seeking without replaying from step 1.</p><h2 id="recursion-example" tabindex="-1">Recursion Example <a class="header-anchor" href="#recursion-example" aria-label="Permalink to &quot;Recursion Example&quot;">​</a></h2><p>Timelines capture recursive execution with full stack depth:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step  4:   METHOD_ENTERED  depth=2  | n=4</span></span>
<span class="line"><span>Step  7:     METHOD_ENTERED  depth=3  | n=3</span></span>
<span class="line"><span>Step 10:       METHOD_ENTERED  depth=4  | n=2</span></span>
<span class="line"><span>Step 13:         METHOD_ENTERED  depth=5  | n=1  (base case)</span></span>
<span class="line"><span>Step 15:         METHOD_EXITED   depth=5  | return 1</span></span>
<span class="line"><span>Step 17:       METHOD_EXITED   depth=4  | return 2</span></span>
<span class="line"><span>Step 19:     METHOD_EXITED   depth=3  | return 6</span></span>
<span class="line"><span>Step 21:   METHOD_EXITED   depth=2  | return 24</span></span></code></pre></div><p>Every recursive call, every parameter value, every return — visible in the timeline.</p>`,15)])])}const E=a(p,[["render",i]]);export{u as __pageData,E as default};
